ProcessCommandLine:
awk -F| '
      BEGIN { c=0; s=0; max=-1; maxp="" }
      {
        c++;
        s += $2;
        # $1 may contain decimals; compare as number
        if ($1 > max) { max=$1; maxp=$3 }
      }
      END {
        # Convert max (seconds with decimals) to int seconds
        maxi = (max < 0 ? "" : int(max));
        # Basic JSON-safe escaping for backslash and quotes in path
        gsub(/\\/,"\\\\",maxp);
        gsub(/"/,"\\\"",maxp);
        printf("{\"path\":\"%s\",\"exists\":true,\"readable\":true,\"file_count\":%d,\"total_bytes\":%.0f,\"newest_mtime_epoch\":\"%s\",\"newest_path\":\"%s\"}",
               "/var/lib/docker/volumes/r0ckyyy335_openemr_sites/_data/default/documents", c, s, maxi, maxp);
      }'

awk '
BEGIN   {
        minus_e = "";
        minus_D = "";
        minus_f = "";
        minus_b = "";
        rest = 0;
} {
        sub(/\r$/, "");
        if (length($0) < 1) { next; }
        if (match($0, "^\\s*#")) { next; }
        if (match($0, "^\\s*-e")) { minus_e = $0; next; }
        if (match($0, "^\\s*-D\\s*$")) { minus_D = $0; next; }
        if (match($0, "^\\s*-f")) { minus_f = $0; next; }
        if (match($0, "^\\s*-b")) { minus_b = $0; next; }
        rules[rest++] = $0;
}
END     {
        printf "%s\n%s\n%s\n", minus_D, minus_b, minus_f;
        for (i = 0; i < rest; i++) { printf "%s\n", rules[i]; }
        printf "%s\n", minus_e;
}'

